import{_ as i,o as r,c as o,a0 as n}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"🤖 Discord 機器人連動指南","description":"","frontmatter":{},"headers":[],"relativePath":"Discord-Integration.md","filePath":"Discord-Integration.md"}'),t={name:"Discord-Integration.md"};function a(e,l,s,d,c,g){return r(),o("div",null,[...l[0]||(l[0]=[n('<h1 id="🤖-discord-機器人連動指南" tabindex="-1">🤖 Discord 機器人連動指南 <a class="header-anchor" href="#🤖-discord-機器人連動指南" aria-label="Permalink to &quot;🤖 Discord 機器人連動指南&quot;">​</a></h1><p>本系統配備了 <strong>Discord 雙向連動機器人</strong>。玩家與管理員可直接在 Discord 頻道中點選按鈕、使用選單與指令，與遊戲伺服器進行即時的資料互通與管理。</p><hr><h2 id="_1-🔑-帳號雙向綁定" tabindex="-1">1. 🔑 帳號雙向綁定 <a class="header-anchor" href="#_1-🔑-帳號雙向綁定" aria-label="Permalink to &quot;1. 🔑 帳號雙向綁定&quot;">​</a></h2><p>為了使用機器人的個人化功能（如餘額查詢、離線信箱與簽到），您必須先將您的 Discord 帳號與 Minecraft 遊戲角色進行綁定：</p><ol><li><strong>獲取驗證碼</strong>：在 Minecraft 遊戲中輸入 <strong><code>/discord link</code></strong>，系統會隨機生成一組 <strong>6 位數字驗證碼</strong>（例如：<code>654321</code>）。</li><li><strong>傳送給機器人</strong>：在 Discord 中私訊本伺服器機器人，直接發送該 6 位數字。</li><li><strong>完成綁定</strong>：機器人驗證成功後會回傳綁定成功訊息，並將您的 Discord 帳號與 Minecraft 角色進行雙向連結。 <ul><li><em>解除綁定</em>：在 Discord 中輸入指令 <strong><code>/解除綁定</code></strong>。</li></ul></li></ol><hr><h2 id="_2-🎮-福利控制面板-key-panel" tabindex="-1">2. 🎮 福利控制面板 (Key Panel) <a class="header-anchor" href="#_2-🎮-福利控制面板-key-panel" aria-label="Permalink to &quot;2. 🎮 福利控制面板 (Key Panel)&quot;">​</a></h2><p>福利控制面板提供玩家每日福利與提醒訂閱功能：</p><ul><li><strong>📅 每日簽到 (Check-in)</strong>： <ul><li>點選按鈕完成當日簽到，系統會隨機發放道具獎勵。</li><li><strong>簽到獎金加碼</strong>：每次簽到皆會<strong>額外獲得 $150 遊戲金幣</strong>！</li><li><strong>連續簽到天數 (Streak)</strong>：系統會累計您的連續簽到天數，天數越高，獲得稀有物品的機率越大。</li></ul></li><li><strong>🔔 訂閱提醒</strong>： <ul><li>點選「訂閱簽到提醒」按鈕，每當簽到重置後，機器人會主動發送 Discord 私訊提醒，避免您的簽到中斷。</li></ul></li><li><strong>🎰 幸運抽獎 (Lucky Draw)</strong>： <ul><li>點選「幸運抽獎」按鈕消耗您的抽獎鑰匙進行抽獎。</li><li><em>限制</em>：玩家必須處於遊戲線上狀態才能進行抽獎。</li><li>每次抽獎皆會<strong>額外保證獲得 $150 金幣</strong>！獎勵會直接在遊戲螢幕上以特效呈現。</li></ul></li><li><strong>🔄 鑰匙實時同步</strong>： <ul><li>當您在 Discord 上完成簽到獲得鑰匙，或點選抽獎消耗鑰匙時，若您的 Minecraft 角色正處於遊戲線上，遊戲內 Scoreboard 個人側邊欄的鑰匙數量將會即時同步更新，無須重登或手動查詢。</li></ul></li></ul><hr><h2 id="_3-🏪-互動控制面板-interaction-panel" tabindex="-1">3. 🏪 互動控制面板 (Interaction Panel) <a class="header-anchor" href="#_3-🏪-互動控制面板-interaction-panel" aria-label="Permalink to &quot;3. 🏪 互動控制面板 (Interaction Panel)&quot;">​</a></h2><p>互動控制面板讓玩家隨時監控個人資產與發送快遞：</p><ul><li><strong>💰 查詢金幣餘額</strong>： <ul><li>點選按鈕，機器人會即時查詢您當前角色的餘額，並以私密訊息回傳：<code>您目前的金幣餘額為：$XXXX 元</code>。</li></ul></li><li><strong>📊 我的商店數據</strong>： <ul><li>點選按鈕即會列出您目前名下所有箱子商店的詳細數據，包括各商店位置、販售商品、單價、庫存與未提領的營收。</li></ul></li><li><strong>📦 離線快遞信箱 (Offline Mailbox)</strong>： <ul><li>當您想轉帳或郵寄物資給其他玩家，但對方不處於線上狀態時，您可以在 Discord 點選「離線快遞」，並選擇收件人與輸入金額或物品。</li><li>系統會暫存該筆快遞。當收件人下次登入遊戲時，伺服器會自動偵測並在聊天欄顯示：<code>📦 [快遞] 收到來自 XXX 的快遞金幣：$XXX 元！</code>，並自動將款項撥入其帳戶。</li></ul></li></ul><hr><h2 id="🛠️-4-管理員控制面板-admin-panel" tabindex="-1">🛠️ 4. 管理員控制面板 (Admin Panel) <a class="header-anchor" href="#🛠️-4-管理員控制面板-admin-panel" aria-label="Permalink to &quot;🛠️ 4. 管理員控制面板 (Admin Panel)&quot;">​</a></h2><p>專為伺服器管理員提供的遠端維護面板（僅限擁有管理人員身分的成員點擊）：</p><ul><li><strong>🚫 封鎖玩家 (Ban)</strong> / <strong>🥾 踢出玩家 (Kick)</strong>： <ul><li>點擊按鈕會彈出輸入框，輸入遊戲 ID 與理由，即可將玩家踢出伺服器或加入黑名單。</li></ul></li><li><strong>📢 發布全服公告</strong>： <ul><li>點選按鈕後輸入公告內容。提交後，遊戲內會以彩色全服公告形式即時傳送給所有線上玩家。</li></ul></li></ul><hr><h2 id="📈-5-經濟與日誌面板" tabindex="-1">📈 5. 經濟與日誌面板 <a class="header-anchor" href="#📈-5-經濟與日誌面板" aria-label="Permalink to &quot;📈 5. 經濟與日誌面板&quot;">​</a></h2><ul><li><strong>🏆 全服富豪排行榜 (Leaderboard)</strong>： <ul><li>點選按鈕，機器人會拉取遊戲內金幣餘額前 10 名的玩家，並在 Discord 頻道中顯示出財富排行榜。</li></ul></li><li><strong>📜 交易即時推播頻道</strong>： <ul><li>只要遊戲內有任何箱子商店成交，伺服器就會即時將交易詳情（買家、賣家、商品、單價、交易數量與印花稅）傳送給 Discord。</li><li>機器人會將其格式化並發送至指定的交易日誌頻道，讓您在 Discord 就能掌握即時的物價波動！</li></ul></li></ul>',21)])])}const p=i(t,[["render",a]]);export{h as __pageData,p as default};
